const crypto = require("crypto");

const required = [
  "eventType",
  "did",
  "contractVersion",
  "archiveEntryId",
  "contentHash",
  "snapshotCid",
  "storedBy",
  "storedAt"
];

for (const key of required) {
  if (!msg.payload || !msg.payload[key]) {
    msg.statusCode = 400;
    msg.payload = { error: `Missing field: ${key}` };
    return msg;
  }
}

const previousHash = flow.get("archiveChainHead") || null;

const auditPayload = {
  eventType: msg.payload.eventType,
  did: msg.payload.did,
  contractVersion: msg.payload.contractVersion,
  archiveEntryId: msg.payload.archiveEntryId,
  contentHash: msg.payload.contentHash,
  snapshotCid: msg.payload.snapshotCid,
  storedBy: msg.payload.storedBy,
  storedAt: msg.payload.storedAt,
  receivedAt: new Date().toISOString(),
  previousHash
};

const canonical = JSON.stringify(auditPayload);
const eventHash = "sha256:" + crypto
  .createHash("sha256")
  .update(canonical)
  .digest("hex");

const storedEvent = {
  ...auditPayload,
  eventHash
};

flow.set("archiveChainHead", eventHash);

msg.payload = JSON.stringify(storedEvent) + "\n";

msg.receipt = {
  receiptType: "ARCHIVE_NOTARY_RECEIPT",
  archiveEntryId: storedEvent.archiveEntryId,
  eventHash: storedEvent.eventHash,
  previousHash: storedEvent.previousHash,
  receivedAt: storedEvent.receivedAt
};

return msg;

msg.statusCode = 200;
msg.headers = {
  "Content-Type": "application/json"
};
msg.payload = msg.receipt;
return msg;

const configuredToken = env.get("ORCE_ARCHIVE_AUDIT_LOG_BEARER_TOKEN") || "dev-archive-audit-token";
const expected = `Bearer ${configuredToken}`;
const actual = msg.req?.headers?.authorization;

if (actual !== expected) {
  msg.statusCode = 401;
  msg.headers = {
    "Content-Type": "application/json"
  };
  msg.payload = { error: "Unauthorized" };
  return [null, msg];
}

return [msg, null];

if (msg.error) {
  msg.statusCode = 404;
  msg.headers = {
    "Content-Type": "application/json"
  };
  msg.payload = {
    error: "Archive audit log file not found",
    path: "/data/archive-audit-events.jsonl"
  };
  return msg;
}

msg.statusCode = 200;
msg.headers = {
  "Content-Type": "text/plain; charset=utf-8"
};

if (msg.payload === undefined || msg.payload === null) {
  msg.payload = "";
}

return msg;
